<script setup lang="ts">
const svc=useAttendanceShifts(); const workspace=useWorkspace(); const feedback=useUiFeedback(); const loading=ref(false); const shifts=ref<any[]>([]); const form=reactive<any>({name:'Default Shift',startTimeMinutes:600,endTimeMinutes:1200,graceMinutes:10,lateAfterMinutes:10,halfDayAfterMinutes:750,minimumFullDayMinutes:480,minimumHalfDayMinutes:240,overtimeAfterMinutes:540,weeklyOffDays:'Sunday',active:true})
async function refresh(){ loading.value=true; try{ shifts.value=await svc.shifts() }catch(e:any){ feedback.fromError('Shifts refresh failed',e) } finally{ loading.value=false } }
async function save(){ await svc.createShift({...form, companyId:workspace.companyId.value, storeGroupId:workspace.storeGroupId.value, storeId:workspace.storeId.value}); await refresh() }
onMounted(refresh)
</script>
<template><AppShell title="Attendance Shifts" @refresh="refresh"><section class="space-y-5"><UiModulePageHeader title="Shifts" description="Shift start/end and late/half-day/overtime rule base." icon="i-lucide-clock-3"><template #actions><UButton label="Refresh" :loading="loading" @click="refresh"/></template></UiModulePageHeader><UCard><div class="grid gap-3 md:grid-cols-4"><UInput v-model="form.name"/><UInput v-model="form.startTimeMinutes" type="number"/><UInput v-model="form.endTimeMinutes" type="number"/><UButton label="Add Shift" @click="save"/></div></UCard><div class="grid gap-3 md:grid-cols-2"><UCard v-for="row in shifts" :key="row.id"><strong>{{ row.name }}</strong><p class="text-xs text-muted">{{ row.startTimeMinutes }} - {{ row.endTimeMinutes }} min · Grace {{ row.graceMinutes }}m · OT after {{ row.overtimeAfterMinutes }}m</p></UCard></div></section></AppShell></template>
